/**
 * MMS Run Assignment Optimizer
 *
 * Main optimizer service that orchestrates between C++ OR-Tools solver
 * and TypeScript fallback. Provides IPC with the C++ binary via
 * NDJSON streams on stdin/stdout.
 *
 * Architecture:
 * - Primary: C++ OR-Tools CP-SAT solver for optimal solutions
 * - Fallback: TypeScript greedy algorithm when C++ unavailable/timeout
 * - Heartbeat monitoring to detect hung processes
 * - Explanation traces for every assignment decision
 *
 * @see specs/002-architecture.md Section 2.4
 * @see specs/004-domain-services.md Section 4.3
 */

import { spawn, type Subprocess } from 'bun';
import { logger } from '../lib/logging/logger';
import { withSpan, recordSpanError } from '../lib/tracing';
import { OptimizerError } from '../lib/errors';
import { optimizerMetrics } from '../lib/metrics';
import { FallbackOptimizer, fallbackOptimizer } from './fallback';
import {
  type OptimizerFullInput,
  type OptimizerFullResult,
  type OptimizerMessage,
  type OptimizerProgressMessage,
  DEFAULT_OPTIMIZER_CONFIG,
} from './types';

// Re-export types
export * from './types';
export { FallbackOptimizer, fallbackOptimizer } from './fallback';

// =============================================================================
// Configuration
// =============================================================================

export interface RunAssignmentOptimizerConfig {
  binaryPath: string;
  maxSolveTimeSeconds: number;
  timeoutMs: number;
  fallbackEnabled: boolean;
  heartbeatIntervalMs: number;
  heartbeatTimeoutMs: number;
}

const DEFAULT_CONFIG: RunAssignmentOptimizerConfig = {
  binaryPath: process.env['MMS_OPTIMIZER_BINARY'] || './mms-optimizer',
  maxSolveTimeSeconds: 30,
  timeoutMs: 60000,
  fallbackEnabled: true,
  heartbeatIntervalMs: 5000,
  heartbeatTimeoutMs: 15000, // 3 missed heartbeats
};

// =============================================================================
// Progress Callback
// =============================================================================

export type ProgressCallback = (progress: OptimizerProgressMessage) => void;

// =============================================================================
// Main Optimizer Service
// =============================================================================

/**
 * Run Assignment Optimizer Service
 *
 * Manages the optimization process, handling both C++ binary
 * execution and TypeScript fallback scenarios.
 */
export class RunAssignmentOptimizer {
  private readonly config: RunAssignmentOptimizerConfig;
  private readonly log = logger.child({ service: 'RunAssignmentOptimizer' });
  private readonly fallback: FallbackOptimizer;
  private process: Subprocess | null = null;
  private heartbeatTimer: Timer | null = null;
  private lastHeartbeat: number = 0;

  constructor(config: Partial<RunAssignmentOptimizerConfig> = {}) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.fallback = fallbackOptimizer;
  }

  /**
   * Run optimization for train-to-route assignment
   *
   * @param input - Optimization input with trains, routes, and constraints
   * @param onProgress - Optional callback for progress updates
   * @returns Optimization result with assignments and explanations
   */
  async optimize(
    input: OptimizerFullInput,
    onProgress?: ProgressCallback
  ): Promise<OptimizerFullResult> {
    return withSpan('optimizer.optimize', async (span) => {
      const startTime = Date.now();

      span.setAttribute('requestId', input.requestId);
      span.setAttribute('trainCount', input.trains.length);
      span.setAttribute('routeCount', input.routes.length);
      span.setAttribute('fallbackEnabled', this.config.fallbackEnabled);

      // Merge default config with input config
      const mergedInput: OptimizerFullInput = {
        ...input,
        config: { ...DEFAULT_OPTIMIZER_CONFIG, ...input.config },
      };

      this.log.info(
        {
          requestId: input.requestId,
          trainCount: input.trains.length,
          routeCount: input.routes.length,
          assignmentDate: input.assignmentDate,
        },
        'Starting optimization'
      );

      try {
        // Try C++ optimizer first
        const result = await this.runCppOptimizer(mergedInput, onProgress);

        // Check if C++ returned INFEASIBLE and fallback is enabled
        if (result.status === 'INFEASIBLE' && this.config.fallbackEnabled) {
          this.log.warn(
            { requestId: input.requestId },
            'C++ optimizer returned INFEASIBLE, using fallback'
          );
          return await this.runWithFallback(mergedInput, startTime);
        }

        optimizerMetrics.optimizerSolveSeconds
          .labels('cpp', result.status)
          .observe(result.solveTimeMs / 1000);

        return result;
      } catch (error) {
        recordSpanError(span, error);

        this.log.error(
          { requestId: input.requestId, error },
          'C++ optimizer failed'
        );

        if (this.config.fallbackEnabled) {
          return await this.runWithFallback(mergedInput, startTime);
        }

        throw error;
      }
    });
  }

  /**
   * Run only the TypeScript fallback optimizer
   *
   * Useful for testing or when C++ binary is not available.
   */
  async optimizeWithFallback(
    input: OptimizerFullInput
  ): Promise<OptimizerFullResult> {
    const mergedInput: OptimizerFullInput = {
      ...input,
      config: { ...DEFAULT_OPTIMIZER_CONFIG, ...input.config },
    };
    return this.fallback.optimize(mergedInput);
  }

  /**
   * Check if C++ optimizer binary is available
   */
  async isCppOptimizerAvailable(): Promise<boolean> {
    try {
      const proc = spawn(['test', '-x', this.config.binaryPath], {
        stdout: 'pipe',
        stderr: 'pipe',
      });
      const code = await proc.exited;
      return code === 0;
    } catch {
      return false;
    }
  }

  /**
   * Run C++ optimizer binary
   */
  private async runCppOptimizer(
    input: OptimizerFullInput,
    onProgress?: ProgressCallback
  ): Promise<OptimizerFullResult> {
    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        this.cleanup();
        reject(
          new OptimizerError(`Optimizer timeout after ${this.config.timeoutMs}ms`, {
            requestId: input.requestId,
            errorCode: 'TIMEOUT',
          })
        );
      }, this.config.timeoutMs);

      // Check if binary exists
      const binaryCheck = spawn(['test', '-x', this.config.binaryPath], {
        stdout: 'pipe',
        stderr: 'pipe',
      });

      binaryCheck.exited.then((code) => {
        if (code !== 0) {
          clearTimeout(timeout);
          reject(
            new OptimizerError('C++ optimizer binary not found or not executable', {
              requestId: input.requestId,
              errorCode: 'BINARY_NOT_FOUND',
              context: { binaryPath: this.config.binaryPath },
            })
          );
          return;
        }

        // Spawn optimizer process
        this.process = spawn([this.config.binaryPath], {
          stdin: 'pipe',
          stdout: 'pipe',
          stderr: 'pipe',
        });

        // Start heartbeat monitor
        this.startHeartbeatMonitor(input.requestId, () => {
          clearTimeout(timeout);
          this.cleanup();
          reject(
            new OptimizerError('Optimizer heartbeat timeout - process may be stuck', {
              requestId: input.requestId,
              errorCode: 'HEARTBEAT_TIMEOUT',
            })
          );
        });

        // Write input to stdin
        const inputJson = JSON.stringify(this.transformInputForCpp(input)) + '\n';
        const stdin = this.process.stdin;
        if (stdin && typeof stdin === 'object' && 'getWriter' in stdin) {
          const writer = (stdin as unknown as WritableStream<Uint8Array>).getWriter();
          writer.write(new TextEncoder().encode(inputJson));
          writer.close();
        }

        // Read stdout
        const stdout = this.process.stdout;
        if (stdout && typeof stdout === 'object' && 'getReader' in stdout) {
          this.readOutputStream(
            stdout as ReadableStream<Uint8Array>,
            input.requestId,
            onProgress,
            (result) => {
              clearTimeout(timeout);
              this.cleanup();
              resolve(result);
            },
            (error) => {
              clearTimeout(timeout);
              this.cleanup();
              reject(error);
            }
          );
        }

        // Read stderr for logs
        const stderr = this.process.stderr;
        if (stderr && typeof stderr === 'object' && 'getReader' in stderr) {
          this.readErrorStream(stderr as ReadableStream<Uint8Array>);
        }

        // Handle process exit
        this.process.exited.then((code) => {
          if (code !== 0) {
            const signal = (this.process as unknown as { signalCode?: string })?.signalCode;
            clearTimeout(timeout);
            this.cleanup();
            reject(
              new OptimizerError(`Optimizer exited with code ${code}`, {
                requestId: input.requestId,
                errorCode: signal === 'SIGSEGV' ? 'SEGFAULT' : 'INTERNAL_ERROR',
                context: { exitCode: code },
              })
            );
          }
        });
      });
    });
  }

  /**
   * Transform input for C++ binary (snake_case)
   */
  private transformInputForCpp(input: OptimizerFullInput): Record<string, unknown> {
    return {
      type: 'SOLVE_REQUEST',
      request_id: input.requestId,
      assignment_date: input.assignmentDate,
      config: {
        max_solve_time_seconds: input.config.maxSolveTimeSeconds,
        num_workers: input.config.numWorkers,
        soft_constraint_penalties: {
          mileage_imbalance: input.config.softConstraintPenalties.mileageImbalance,
          preference_violation: input.config.softConstraintPenalties.preferenceViolation,
          overtime_hours: input.config.softConstraintPenalties.overtimeHours,
        },
        explanation_verbosity: input.config.explanationVerbosity,
      },
      trains: input.trains.map((t) => ({
        id: t.id,
        train_number: t.trainNumber,
        fleet_id: t.fleetId,
        current_mileage: t.currentMileageKm,
        target_mileage: t.targetMileageKm,
        fitness_status: t.fitnessStatus,
        restrictions: t.restrictions,
        home_depot_id: t.homeDepotId,
        current_depot_id: t.currentDepotId,
      })),
      routes: input.routes.map((r) => ({
        id: r.id,
        route_code: r.routeCode,
        expected_km: r.expectedKmPerDay,
        required_trains: r.requiredTrains,
        allowed_fleets: r.allowedFleetIds,
        restrictions: r.restrictions,
      })),
      hard_constraints: input.hardConstraints.map((c) => ({
        type: c.type,
        train_id: c.trainId,
        route_id: c.routeId,
        description: c.description,
      })),
      soft_constraints: input.softConstraints.map((c) => ({
        type: c.type,
        train_id: c.trainId,
        penalty_weight: c.penaltyWeight,
        description: c.description,
      })),
      unavailability_events: input.unavailabilityEvents?.map((e) => ({
        train_id: e.trainId,
        event_type: e.eventType,
        status: e.status,
        blocks_run_assignment: e.blocksRunAssignment,
        description: e.description,
        external_reference: e.externalReference,
      })),
      route_compatibility: input.routeCompatibility?.map((c) => ({
        train_id: c.trainId,
        fleet_id: c.fleetId,
        route_id: c.routeId,
        is_compatible: c.isCompatible,
        constraint_type: c.constraintType,
        restriction_reason: c.restrictionReason,
      })),
      material_positions: input.materialPositions?.map((p) => ({
        depot_id: p.depotId,
        part_number: p.partNumber,
        quantity_available: p.quantityAvailable,
        next_delivery_date: p.nextDeliveryDate,
      })),
      pending_pms: input.pendingPms?.map((pm) => ({
        pm_id: pm.pmId,
        train_id: pm.trainId,
        pm_type: pm.pmType,
        target_date: pm.targetDate,
        required_materials: pm.requiredMaterials.map((m) => ({
          part_number: m.partNumber,
          quantity: m.quantity,
          criticality: m.criticality,
        })),
      })),
      service_demand: input.serviceDemand?.map((d) => ({
        fleet_id: d.fleetId,
        min_trains_required: d.minTrainsRequired,
        day_type: d.dayType,
      })),
    };
  }

  /**
   * Read and parse output stream
   */
  private async readOutputStream(
    stream: ReadableStream<Uint8Array>,
    requestId: string,
    onProgress: ProgressCallback | undefined,
    onResult: (result: OptimizerFullResult) => void,
    onError: (error: Error) => void
  ): Promise<void> {
    const reader = stream.getReader();
    const decoder = new TextDecoder();
    let buffer = '';

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        for (const line of lines) {
          if (!line.trim()) continue;

          try {
            const msg = JSON.parse(line) as OptimizerMessage;
            this.handleMessage(msg, requestId, onProgress, onResult, onError);
          } catch (parseError) {
            this.log.warn({ line, parseError }, 'Failed to parse optimizer output');
          }
        }
      }
    } catch (error) {
      this.log.error({ error }, 'Error reading optimizer output stream');
      onError(error instanceof Error ? error : new Error(String(error)));
    }
  }

  /**
   * Handle parsed optimizer message
   */
  private handleMessage(
    msg: OptimizerMessage,
    requestId: string,
    onProgress: ProgressCallback | undefined,
    onResult: (result: OptimizerFullResult) => void,
    onError: (error: Error) => void
  ): void {
    switch (msg.type) {
      case 'HEARTBEAT':
        this.lastHeartbeat = Date.now();
        break;

      case 'PROGRESS':
        this.lastHeartbeat = Date.now();
        if (onProgress) {
          onProgress(msg);
        }
        break;

      case 'ERROR':
        onError(
          new OptimizerError(msg.errorMessage, {
            requestId,
            errorCode: msg.errorCode,
            recoverySuggestion: msg.recoverySuggestion,
          })
        );
        break;

      case 'RESULT':
        onResult(this.transformResultFromCpp(msg as unknown as Record<string, unknown>));
        break;
    }
  }

  /**
   * Transform result from C++ (snake_case to camelCase)
   */
  private transformResultFromCpp(msg: Record<string, unknown>): OptimizerFullResult {
    const assignments = (msg['assignments'] as Record<string, unknown>[])?.map((a) => ({
      trainId: a['train_id'] as string,
      routeId: a['route_id'] as string,
      score: a['score'] as number,
      explanation: (a['explanation'] as Record<string, unknown>[])?.map((e) => ({
        constraintType: e['constraint_type'] as 'HARD' | 'SOFT',
        constraintName: e['constraint_name'] as string,
        impact: e['impact'] as number,
        description: e['description'] as string,
      })) || [],
    })) || [];

    const unassigned = (msg['unassigned'] as Record<string, unknown>[])?.map((u) => ({
      trainId: u['train_id'] as string | undefined,
      routeId: u['route_id'] as string | undefined,
      shortfall: u['shortfall'] as number | undefined,
      reason: u['reason'] as string,
      blockingConstraints: (u['blocking_constraints'] as string[]) || [],
    })) || [];

    const materialWarnings = (msg['material_warnings'] as Record<string, unknown>[])?.map((w) => ({
      pmId: w['pm_id'] as string,
      trainId: w['train_id'] as string,
      partNumber: w['part_number'] as string,
      status: w['status'] as 'UNAVAILABLE' | 'LOW_STOCK' | 'ARRIVING_LATE',
      description: w['description'] as string,
    })) || [];

    const summary = msg['summary'] as Record<string, unknown>;

    return {
      type: 'RESULT',
      requestId: msg['request_id'] as string,
      status: msg['status'] as 'OPTIMAL' | 'FEASIBLE' | 'FALLBACK' | 'INFEASIBLE',
      solveTimeMs: msg['solve_time_ms'] as number,
      assignments,
      unassigned,
      materialWarnings,
      summary: {
        totalPenalty: summary?.['total_penalty'] as number || 0,
        trainsAssigned: summary?.['trains_assigned'] as number || assignments.length,
        trainsUnassigned: summary?.['trains_unassigned'] as number || unassigned.length,
        softConstraintBreakdown: (summary?.['soft_constraint_breakdown'] as Record<string, number>) || {},
        materialBlocks: summary?.['material_blocks'] as number || 0,
      },
    };
  }

  /**
   * Read stderr for logs/metrics
   */
  private async readErrorStream(stream: ReadableStream<Uint8Array>): Promise<void> {
    const reader = stream.getReader();
    const decoder = new TextDecoder();

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const text = decoder.decode(value, { stream: true });
        for (const line of text.split('\n')) {
          if (line.trim()) {
            this.log.debug({ stderr: line }, 'Optimizer stderr');
          }
        }
      }
    } catch {
      // Ignore stderr errors
    }
  }

  /**
   * Start heartbeat monitoring
   */
  private startHeartbeatMonitor(
    requestId: string,
    onTimeout: () => void
  ): void {
    this.lastHeartbeat = Date.now();

    this.heartbeatTimer = setInterval(() => {
      const elapsed = Date.now() - this.lastHeartbeat;

      if (elapsed > this.config.heartbeatTimeoutMs) {
        this.log.error(
          { requestId, elapsedMs: elapsed },
          'Heartbeat timeout - killing optimizer process'
        );

        // Kill hung process
        if (this.process) {
          this.process.kill('SIGKILL');
        }

        onTimeout();
      }
    }, this.config.heartbeatIntervalMs);
  }

  /**
   * Run fallback optimizer
   */
  private async runWithFallback(
    input: OptimizerFullInput,
    startTime: number
  ): Promise<OptimizerFullResult> {
    this.log.info({ requestId: input.requestId }, 'Running fallback optimizer');

    const result = await this.fallback.optimize(input);

    optimizerMetrics.optimizerSolveSeconds
      .labels('fallback', result.status)
      .observe((Date.now() - startTime) / 1000);

    return result;
  }

  /**
   * Cleanup resources
   */
  private cleanup(): void {
    if (this.heartbeatTimer) {
      clearInterval(this.heartbeatTimer);
      this.heartbeatTimer = null;
    }

    if (this.process) {
      try {
        this.process.kill();
      } catch {
        // Ignore kill errors
      }
      this.process = null;
    }
  }
}

// Export singleton instance
export const runAssignmentOptimizer = new RunAssignmentOptimizer();

