/**
 * MMS Optimizer IPC Protocol Implementation
 */

#include "ipc.h"
#include <iostream>
#include <sstream>
#include <cstring>
#include <csignal>

#ifdef __linux__
#include <sys/resource.h>
#elif __APPLE__
#include <mach/mach.h>
#endif

namespace mms {

IpcHandler::IpcHandler()
    : startTime_(std::chrono::steady_clock::now())
{
}

IpcHandler::~IpcHandler() {
    stopHeartbeatThread();
}

json IpcHandler::readInput() {
    std::string line;
    if (!std::getline(std::cin, line)) {
        throw std::runtime_error("Failed to read input from stdin");
    }

    try {
        return json::parse(line);
    } catch (const json::parse_error& e) {
        throw std::runtime_error(
            std::string("Invalid JSON input: ") + e.what()
        );
    }
}

void IpcHandler::sendHeartbeat(
    const std::string& requestId,
    double memoryMb,
    int threadCount,
    double branchesPerSecond
) {
    json msg;
    msg["type"] = "HEARTBEAT";
    msg["request_id"] = requestId;
    msg["timestamp"] = std::chrono::duration_cast<std::chrono::milliseconds>(
        std::chrono::system_clock::now().time_since_epoch()
    ).count();
    msg["memory_mb"] = memoryMb;
    msg["thread_count"] = threadCount;
    msg["branches_per_second"] = branchesPerSecond;

    sendMessage(msg);
}

void IpcHandler::sendProgress(
    const std::string& requestId,
    double percent,
    double currentObjective,
    bool feasible,
    int64_t elapsedMs
) {
    // Update state for heartbeat thread
    lastPercent_.store(percent);
    lastObjective_.store(currentObjective);
    lastFeasible_.store(feasible);

    json msg;
    msg["type"] = "PROGRESS";
    msg["request_id"] = requestId;
    msg["percent"] = percent;
    msg["current_objective"] = currentObjective;
    msg["feasible"] = feasible;
    msg["elapsed_ms"] = elapsedMs;

    sendMessage(msg);
}

void IpcHandler::sendError(
    const std::string& requestId,
    ErrorCode code,
    const std::string& message,
    const std::string& stackTrace,
    const std::string& recoverySuggestion
) {
    stopHeartbeatThread();

    json msg;
    msg["type"] = "ERROR";
    msg["request_id"] = requestId;
    msg["error_code"] = errorCodeToString(code);
    msg["error_message"] = message;

    if (!stackTrace.empty()) {
        msg["stack_trace"] = stackTrace;
    }

    json lastProgress;
    lastProgress["percent"] = lastPercent_.load();
    lastProgress["branches_explored"] = branchesExplored_.load();
    lastProgress["memory_mb"] = getMemoryUsageMb();
    msg["last_progress"] = lastProgress;

    if (!recoverySuggestion.empty()) {
        msg["recovery_suggestion"] = recoverySuggestion;
    } else {
        // Default recovery suggestions based on error code
        switch (code) {
            case ErrorCode::TIMEOUT:
                msg["recovery_suggestion"] = "Consider increasing max_solve_time_seconds or simplifying the problem";
                break;
            case ErrorCode::OOM:
                msg["recovery_suggestion"] = "Reduce problem size or increase container memory limits";
                break;
            case ErrorCode::INVALID_INPUT:
                msg["recovery_suggestion"] = "Validate input JSON schema and constraint consistency";
                break;
            default:
                msg["recovery_suggestion"] = "Check logs for details and retry";
                break;
        }
    }

    sendMessage(msg);

    // Exit with non-zero code for error
    std::exit(1);
}

void IpcHandler::sendResult(const json& result) {
    stopHeartbeatThread();
    sendMessage(result);
}

void IpcHandler::startHeartbeatThread(const std::string& requestId, int intervalMs) {
    if (heartbeatRunning_.load()) {
        return; // Already running
    }

    heartbeatRunning_.store(true);
    heartbeatThread_ = std::thread(&IpcHandler::heartbeatLoop, this, requestId, intervalMs);
}

void IpcHandler::stopHeartbeatThread() {
    heartbeatRunning_.store(false);
    if (heartbeatThread_.joinable()) {
        heartbeatThread_.join();
    }
}

void IpcHandler::updateProgress(double percent, double objective, bool feasible) {
    lastPercent_.store(percent);
    lastObjective_.store(objective);
    lastFeasible_.store(feasible);
}

int64_t IpcHandler::getElapsedMs() const {
    return std::chrono::duration_cast<std::chrono::milliseconds>(
        std::chrono::steady_clock::now() - startTime_
    ).count();
}

void IpcHandler::sendMessage(const json& msg) {
    std::lock_guard<std::mutex> lock(outputMutex_);
    std::cout << msg.dump() << '\n';
    std::cout.flush();
}

double IpcHandler::getMemoryUsageMb() const {
#ifdef __linux__
    struct rusage usage;
    if (getrusage(RUSAGE_SELF, &usage) == 0) {
        return static_cast<double>(usage.ru_maxrss) / 1024.0; // KB to MB
    }
#elif __APPLE__
    struct mach_task_basic_info info;
    mach_msg_type_number_t size = MACH_TASK_BASIC_INFO_COUNT;
    if (task_info(mach_task_self(), MACH_TASK_BASIC_INFO,
                  reinterpret_cast<task_info_t>(&info), &size) == KERN_SUCCESS) {
        return static_cast<double>(info.resident_size) / (1024.0 * 1024.0);
    }
#endif
    return 0.0;
}

void IpcHandler::heartbeatLoop(const std::string& requestId, int intervalMs) {
    while (heartbeatRunning_.load()) {
        std::this_thread::sleep_for(std::chrono::milliseconds(intervalMs));

        if (!heartbeatRunning_.load()) {
            break;
        }

        // Calculate branches per second (estimated)
        int64_t elapsed = getElapsedMs();
        double branchesPerSecond = elapsed > 0
            ? static_cast<double>(branchesExplored_.load()) / (elapsed / 1000.0)
            : 0.0;

        sendHeartbeat(
            requestId,
            getMemoryUsageMb(),
            std::thread::hardware_concurrency(),
            branchesPerSecond
        );
    }
}

std::string errorCodeToString(ErrorCode code) {
    switch (code) {
        case ErrorCode::SEGFAULT: return "SEGFAULT";
        case ErrorCode::TIMEOUT: return "TIMEOUT";
        case ErrorCode::OOM: return "OOM";
        case ErrorCode::INVALID_INPUT: return "INVALID_INPUT";
        case ErrorCode::INTERNAL_ERROR: return "INTERNAL_ERROR";
        default: return "UNKNOWN";
    }
}

} // namespace mms

/**
 * MMS Optimizer IPC Protocol
 *
 * Handles NDJSON communication with the TypeScript wrapper.
 * Protocol:
 *   - Input: Single JSON object on stdin (newline-terminated)
 *   - Output: NDJSON stream on stdout (HEARTBEAT, PROGRESS, ERROR, RESULT)
 *
 * @see specs/004-domain-services.md Section 4.3.2
 */

#pragma once

#include <nlohmann/json.hpp>
#include <string>
#include <chrono>
#include <thread>
#include <atomic>
#include <mutex>

namespace mms {

using json = nlohmann::json;

/**
 * Message types sent to stdout
 */
enum class MessageType {
    HEARTBEAT,
    PROGRESS,
    ERROR,
    RESULT
};

/**
 * Error codes for ERROR messages
 */
enum class ErrorCode {
    SEGFAULT,
    TIMEOUT,
    OOM,
    INVALID_INPUT,
    INTERNAL_ERROR
};

/**
 * IPC Handler for NDJSON communication
 *
 * Thread-safe output handling with heartbeat support.
 */
class IpcHandler {
public:
    IpcHandler();
    ~IpcHandler();

    // Prevent copying
    IpcHandler(const IpcHandler&) = delete;
    IpcHandler& operator=(const IpcHandler&) = delete;

    /**
     * Read input from stdin
     * @return Parsed JSON input or throws on invalid JSON
     */
    json readInput();

    /**
     * Send heartbeat message
     * @param requestId Request ID for correlation
     * @param memoryMb Current memory usage in MB
     * @param threadCount Number of active threads
     * @param branchesPerSecond Solver branches per second
     */
    void sendHeartbeat(
        const std::string& requestId,
        double memoryMb,
        int threadCount,
        double branchesPerSecond
    );

    /**
     * Send progress update
     * @param requestId Request ID for correlation
     * @param percent Progress percentage (0-100)
     * @param currentObjective Current objective value
     * @param feasible Whether current solution is feasible
     * @param elapsedMs Elapsed time in milliseconds
     */
    void sendProgress(
        const std::string& requestId,
        double percent,
        double currentObjective,
        bool feasible,
        int64_t elapsedMs
    );

    /**
     * Send error message and exit
     * @param requestId Request ID for correlation
     * @param code Error code
     * @param message Error message
     * @param stackTrace Optional stack trace
     * @param recoverySuggestion Suggestion for recovery
     */
    [[noreturn]] void sendError(
        const std::string& requestId,
        ErrorCode code,
        const std::string& message,
        const std::string& stackTrace = "",
        const std::string& recoverySuggestion = ""
    );

    /**
     * Send result and exit successfully
     * @param result Complete result JSON object
     */
    void sendResult(const json& result);

    /**
     * Start background heartbeat thread
     * @param requestId Request ID for correlation
     * @param intervalMs Heartbeat interval in milliseconds
     */
    void startHeartbeatThread(const std::string& requestId, int intervalMs = 5000);

    /**
     * Stop background heartbeat thread
     */
    void stopHeartbeatThread();

    /**
     * Update progress info for heartbeat thread
     */
    void updateProgress(double percent, double objective, bool feasible);

    /**
     * Get elapsed time since start
     */
    int64_t getElapsedMs() const;

private:
    /**
     * Send JSON message to stdout (thread-safe)
     */
    void sendMessage(const json& msg);

    /**
     * Get current memory usage in MB
     */
    double getMemoryUsageMb() const;

    /**
     * Heartbeat thread function
     */
    void heartbeatLoop(const std::string& requestId, int intervalMs);

    std::mutex outputMutex_;
    std::atomic<bool> heartbeatRunning_{false};
    std::thread heartbeatThread_;

    // Progress state for heartbeat
    std::atomic<double> lastPercent_{0.0};
    std::atomic<double> lastObjective_{0.0};
    std::atomic<bool> lastFeasible_{false};
    std::atomic<int64_t> branchesExplored_{0};

    std::chrono::steady_clock::time_point startTime_;
};

/**
 * Convert ErrorCode to string
 */
std::string errorCodeToString(ErrorCode code);

} // namespace mms

