/**
 * MMS Run Assignment Solver Implementation
 *
 * Uses Google OR-Tools CP-SAT solver for constraint-based optimization.
 * Implements all hard/soft constraints from spec 004.
 */

#include "solver.h"
#include <ortools/sat/cp_model.h>
#include <chrono>
#include <algorithm>
#include <sstream>
#include <cmath>

#ifdef HAS_FMT
#include <fmt/format.h>
#else
#include <cstdio>
#endif

namespace mms {

using namespace operations_research::sat;

// =============================================================================
// JSON Serialization
// =============================================================================

json ExplanationFactor::toJson() const {
    return {
        {"constraint_type", constraintType},
        {"constraint_name", constraintName},
        {"impact", impact},
        {"description", description}
    };
}

json Assignment::toJson() const {
    json expJson = json::array();
    for (const auto& e : explanation) {
        expJson.push_back(e.toJson());
    }
    return {
        {"train_id", trainId},
        {"route_id", routeId},
        {"score", score},
        {"explanation", expJson}
    };
}

json Unassigned::toJson() const {
    json result;
    if (trainId) result["train_id"] = *trainId;
    if (routeId) result["route_id"] = *routeId;
    if (shortfall) result["shortfall"] = *shortfall;
    result["reason"] = reason;
    result["blocking_constraints"] = blockingConstraints;
    return result;
}

json MaterialWarning::toJson() const {
    return {
        {"pm_id", pmId},
        {"train_id", trainId},
        {"part_number", partNumber},
        {"status", status},
        {"description", description}
    };
}

json ResultSummary::toJson() const {
    json breakdown;
    for (const auto& [key, value] : softConstraintBreakdown) {
        breakdown[key] = value;
    }
    return {
        {"total_penalty", totalPenalty},
        {"trains_assigned", trainsAssigned},
        {"trains_unassigned", trainsUnassigned},
        {"soft_constraint_breakdown", breakdown},
        {"material_blocks", materialBlocks}
    };
}

json SolverResult::toJson() const {
    json assignmentsJson = json::array();
    for (const auto& a : assignments) {
        assignmentsJson.push_back(a.toJson());
    }

    json unassignedJson = json::array();
    for (const auto& u : unassigned) {
        unassignedJson.push_back(u.toJson());
    }

    json warningsJson = json::array();
    for (const auto& w : materialWarnings) {
        warningsJson.push_back(w.toJson());
    }

    return {
        {"type", "RESULT"},
        {"request_id", requestId},
        {"status", status},
        {"solve_time_ms", solveTimeMs},
        {"assignments", assignmentsJson},
        {"unassigned", unassignedJson},
        {"material_warnings", warningsJson},
        {"summary", summary.toJson()}
    };
}

// =============================================================================
// Solver Implementation
// =============================================================================

MmsSolver::MmsSolver() = default;

std::string MmsSolver::validateInput(const json& input) const {
    if (!input.contains("request_id")) {
        return "Missing required field: request_id";
    }
    if (!input.contains("trains") || !input["trains"].is_array()) {
        return "Missing or invalid field: trains (must be array)";
    }
    if (!input.contains("routes") || !input["routes"].is_array()) {
        return "Missing or invalid field: routes (must be array)";
    }
    if (input["trains"].empty()) {
        return "trains array is empty";
    }
    if (input["routes"].empty()) {
        return "routes array is empty";
    }
    return "";
}

SolverResult MmsSolver::solve(const json& input, ProgressCallback onProgress) {
    auto startTime = std::chrono::steady_clock::now();

    // Parse input
    std::string requestId = input["request_id"].get<std::string>();
    auto trains = parseTrains(input);
    auto routes = parseRoutes(input);
    auto hardConstraints = parseHardConstraints(input);
    auto softConstraints = parseSoftConstraints(input);
    auto unavailabilityEvents = parseUnavailabilityEvents(input);
    auto routeCompatibility = parseRouteCompatibility(input);
    auto config = parseConfig(input);

    // Build CP-SAT model
    CpModelBuilder model;

    // Decision variables: assign[t][r] = 1 if train t assigned to route r
    std::vector<std::vector<BoolVar>> assign(trains.size());
    for (size_t t = 0; t < trains.size(); ++t) {
        assign[t].resize(routes.size());
        for (size_t r = 0; r < routes.size(); ++r) {
            assign[t][r] = model.NewBoolVar();
        }
    }

    // =========================================================================
    // HARD CONSTRAINTS
    // =========================================================================

    // 1. Each train assigned to at most one route
    for (size_t t = 0; t < trains.size(); ++t) {
        std::vector<BoolVar> trainRoutes;
        for (size_t r = 0; r < routes.size(); ++r) {
            trainRoutes.push_back(assign[t][r]);
        }
        model.AddAtMostOne(trainRoutes);
    }

    // 2. Route requirements (exactly N trains)
    for (size_t r = 0; r < routes.size(); ++r) {
        std::vector<BoolVar> routeTrains;
        for (size_t t = 0; t < trains.size(); ++t) {
            // Only include trains that are fleet-compatible
            if (isFleetAllowed(trains[t], routes[r])) {
                routeTrains.push_back(assign[t][r]);
            } else {
                // Force incompatible assignments to 0
                model.AddEquality(assign[t][r], 0);
            }
        }

        // Require exactly N trains for this route
        if (routeTrains.size() >= static_cast<size_t>(routes[r].requiredTrains)) {
            model.AddEquality(LinearExpr::Sum(routeTrains), routes[r].requiredTrains);
        }
    }

    // 3. Fitness status - GROUNDED/RESTRICTED trains cannot be assigned
    for (size_t t = 0; t < trains.size(); ++t) {
        if (trains[t].fitnessStatus == "GROUNDED") {
            for (size_t r = 0; r < routes.size(); ++r) {
                model.AddEquality(assign[t][r], 0);
            }
        }
    }

    // 4. Hard constraints from input (PM_DUE, DEPOT_LOCK, etc.)
    for (const auto& constraint : hardConstraints) {
        size_t trainIdx = findTrainIndex(trains, constraint.trainId);
        if (trainIdx < trains.size()) {
            if (constraint.routeId) {
                // Block specific train-route combination
                size_t routeIdx = findRouteIndex(routes, *constraint.routeId);
                if (routeIdx < routes.size()) {
                    model.AddEquality(assign[trainIdx][routeIdx], 0);
                }
            } else {
                // Block train from all routes
                for (size_t r = 0; r < routes.size(); ++r) {
                    model.AddEquality(assign[trainIdx][r], 0);
                }
            }
        }
    }

    // 5. Unavailability events - block ACTIVE events with blocksRunAssignment
    for (const auto& event : unavailabilityEvents) {
        if (event.status == "ACTIVE" && event.blocksRunAssignment) {
            size_t trainIdx = findTrainIndex(trains, event.trainId);
            if (trainIdx < trains.size()) {
                for (size_t r = 0; r < routes.size(); ++r) {
                    model.AddEquality(assign[trainIdx][r], 0);
                }
            }
        }
    }

    // 6. Route compatibility matrix
    for (const auto& compat : routeCompatibility) {
        if (!compat.isCompatible) {
            size_t routeIdx = findRouteIndex(routes, compat.routeId);
            if (routeIdx >= routes.size()) continue;

            if (compat.trainId) {
                // Train-specific incompatibility
                size_t trainIdx = findTrainIndex(trains, *compat.trainId);
                if (trainIdx < trains.size()) {
                    model.AddEquality(assign[trainIdx][routeIdx], 0);
                }
            } else if (compat.fleetId) {
                // Fleet-wide incompatibility
                for (size_t t = 0; t < trains.size(); ++t) {
                    if (trains[t].fleetId == *compat.fleetId) {
                        model.AddEquality(assign[t][routeIdx], 0);
                    }
                }
            }
        }
    }

    // =========================================================================
    // SOFT CONSTRAINTS (Penalties)
    // =========================================================================

    std::vector<IntVar> penalties;

    // Mileage imbalance penalty
    for (size_t t = 0; t < trains.size(); ++t) {
        int current = trains[t].currentMileage;
        int target = trains[t].targetMileage;
        int variance = std::abs(current - target);

        for (size_t r = 0; r < routes.size(); ++r) {
            int routeKm = routes[r].expectedKm;

            // Penalty for assigning over-utilized train to high-km route
            if (current > target && routeKm > 200) {
                int penaltyValue = (variance * config.mileageImbalancePenalty) / 1000;

                IntVar penalty = model.NewIntVar({0, penaltyValue});
                model.AddEquality(penalty, penaltyValue).OnlyEnforceIf(assign[t][r]);
                model.AddEquality(penalty, 0).OnlyEnforceIf(assign[t][r].Not());
                penalties.push_back(penalty);
            }

            // Bonus for assigning under-utilized train to high-km route
            // (negative penalty = bonus)
            if (current < target && routeKm > 200) {
                int bonusValue = -(variance * config.mileageImbalancePenalty) / 2000;

                IntVar bonus = model.NewIntVar({bonusValue, 0});
                model.AddEquality(bonus, bonusValue).OnlyEnforceIf(assign[t][r]);
                model.AddEquality(bonus, 0).OnlyEnforceIf(assign[t][r].Not());
                penalties.push_back(bonus);
            }
        }
    }

    // Soft constraints from input
    for (const auto& constraint : softConstraints) {
        size_t trainIdx = findTrainIndex(trains, constraint.trainId);
        if (trainIdx < trains.size()) {
            // Apply penalty when train is assigned anywhere
            for (size_t r = 0; r < routes.size(); ++r) {
                IntVar penalty = model.NewIntVar({0, constraint.penaltyWeight});
                model.AddEquality(penalty, constraint.penaltyWeight).OnlyEnforceIf(assign[trainIdx][r]);
                model.AddEquality(penalty, 0).OnlyEnforceIf(assign[trainIdx][r].Not());
                penalties.push_back(penalty);
            }
        }
    }

    // =========================================================================
    // OBJECTIVE: Minimize total penalty
    // =========================================================================

    if (!penalties.empty()) {
        model.Minimize(LinearExpr::Sum(penalties));
    }

    // =========================================================================
    // SOLVER CONFIGURATION
    // =========================================================================

    SatParameters params;
    params.set_max_time_in_seconds(static_cast<double>(config.maxSolveTimeSeconds));
    params.set_num_search_workers(config.numWorkers);
    params.set_log_search_progress(false);

    Model cpModel;
    cpModel.Add(NewSatParameters(params));

    // Progress callback for solution observer
    int callbackCount = 0;
    if (onProgress) {
        cpModel.Add(NewFeasibleSolutionObserver([&](const CpSolverResponse& response) {
            callbackCount++;
            if (callbackCount % 5 == 0) {
                double percent = std::min(90.0, static_cast<double>(callbackCount) * 3.0);
                onProgress(percent, response.objective_value(), true);
            }
        }));
    }

    // =========================================================================
    // SOLVE
    // =========================================================================

    CpSolverResponse response = SolveCpModel(model.Build(), &cpModel);

    auto endTime = std::chrono::steady_clock::now();
    int64_t solveTimeMs = std::chrono::duration_cast<std::chrono::milliseconds>(
        endTime - startTime
    ).count();

    // Final progress update
    if (onProgress) {
        onProgress(100.0, response.objective_value(),
            response.status() == CpSolverStatus::OPTIMAL ||
            response.status() == CpSolverStatus::FEASIBLE);
    }

    // =========================================================================
    // BUILD RESULT
    // =========================================================================

    SolverResult result;
    result.requestId = requestId;
    result.solveTimeMs = solveTimeMs;

    if (response.status() == CpSolverStatus::OPTIMAL) {
        result.status = "OPTIMAL";
    } else if (response.status() == CpSolverStatus::FEASIBLE) {
        result.status = "FEASIBLE";
    } else {
        result.status = "INFEASIBLE";
        result.unassigned = findUnassigned(trains, routes, {}, input);
        result.summary = buildSummary({}, result.unassigned, -1.0);
        return result;
    }

    // Extract assignments
    for (size_t t = 0; t < trains.size(); ++t) {
        for (size_t r = 0; r < routes.size(); ++r) {
            if (SolutionBooleanValue(response, assign[t][r])) {
                Assignment assignment;
                assignment.trainId = trains[t].id;
                assignment.routeId = routes[r].id;
                assignment.score = 1.0 - (response.objective_value() / 10000.0);
                assignment.explanation = generateExplanation(
                    trains[t], routes[r], input, response.objective_value()
                );
                result.assignments.push_back(assignment);
            }
        }
    }

    result.unassigned = findUnassigned(trains, routes, result.assignments, input);
    result.materialWarnings = checkMaterialWarnings(input);
    result.summary = buildSummary(result.assignments, result.unassigned, response.objective_value());

    return result;
}

// =============================================================================
// Input Parsing
// =============================================================================

std::vector<MmsSolver::Train> MmsSolver::parseTrains(const json& input) {
    std::vector<Train> trains;
    for (const auto& t : input["trains"]) {
        Train train;
        train.id = t["id"].get<std::string>();
        train.trainNumber = t.value("train_number", "");
        train.fleetId = t.value("fleet_id", "");
        train.currentMileage = t.value("current_mileage", 0);
        train.targetMileage = t.value("target_mileage", 0);
        train.fitnessStatus = t.value("fitness_status", "FIT");
        train.homeDepotId = t.value("home_depot_id", "");
        train.currentDepotId = t.value("current_depot_id", "");

        if (t.contains("restrictions") && t["restrictions"].is_array()) {
            for (const auto& r : t["restrictions"]) {
                train.restrictions.push_back(r.get<std::string>());
            }
        }

        trains.push_back(train);
    }
    return trains;
}

std::vector<MmsSolver::Route> MmsSolver::parseRoutes(const json& input) {
    std::vector<Route> routes;
    for (const auto& r : input["routes"]) {
        Route route;
        route.id = r["id"].get<std::string>();
        route.routeCode = r.value("route_code", "");
        route.expectedKm = r.value("expected_km", 0);
        route.requiredTrains = r.value("required_trains", 1);

        if (r.contains("allowed_fleets") && r["allowed_fleets"].is_array()) {
            for (const auto& f : r["allowed_fleets"]) {
                route.allowedFleets.push_back(f.get<std::string>());
            }
        }

        if (r.contains("restrictions") && r["restrictions"].is_array()) {
            for (const auto& x : r["restrictions"]) {
                route.restrictions.push_back(x.get<std::string>());
            }
        }

        routes.push_back(route);
    }
    return routes;
}

std::vector<MmsSolver::HardConstraint> MmsSolver::parseHardConstraints(const json& input) {
    std::vector<HardConstraint> constraints;
    if (!input.contains("hard_constraints")) return constraints;

    for (const auto& c : input["hard_constraints"]) {
        HardConstraint constraint;
        constraint.type = c["type"].get<std::string>();
        constraint.trainId = c["train_id"].get<std::string>();
        if (c.contains("route_id") && !c["route_id"].is_null()) {
            constraint.routeId = c["route_id"].get<std::string>();
        }
        constraint.description = c.value("description", "");
        constraints.push_back(constraint);
    }
    return constraints;
}

std::vector<MmsSolver::SoftConstraint> MmsSolver::parseSoftConstraints(const json& input) {
    std::vector<SoftConstraint> constraints;
    if (!input.contains("soft_constraints")) return constraints;

    for (const auto& c : input["soft_constraints"]) {
        SoftConstraint constraint;
        constraint.type = c["type"].get<std::string>();
        constraint.trainId = c["train_id"].get<std::string>();
        constraint.penaltyWeight = c.value("penalty_weight", 50);
        constraint.description = c.value("description", "");
        constraints.push_back(constraint);
    }
    return constraints;
}

std::vector<MmsSolver::UnavailabilityEvent> MmsSolver::parseUnavailabilityEvents(const json& input) {
    std::vector<UnavailabilityEvent> events;
    if (!input.contains("unavailability_events")) return events;

    for (const auto& e : input["unavailability_events"]) {
        UnavailabilityEvent event;
        event.trainId = e["train_id"].get<std::string>();
        event.eventType = e.value("event_type", "");
        event.status = e.value("status", "ACTIVE");
        event.blocksRunAssignment = e.value("blocks_run_assignment", false);
        event.description = e.value("description", "");
        events.push_back(event);
    }
    return events;
}

std::vector<MmsSolver::RouteCompatibility> MmsSolver::parseRouteCompatibility(const json& input) {
    std::vector<RouteCompatibility> compat;
    if (!input.contains("route_compatibility")) return compat;

    for (const auto& c : input["route_compatibility"]) {
        RouteCompatibility rc;
        if (c.contains("train_id") && !c["train_id"].is_null()) {
            rc.trainId = c["train_id"].get<std::string>();
        }
        if (c.contains("fleet_id") && !c["fleet_id"].is_null()) {
            rc.fleetId = c["fleet_id"].get<std::string>();
        }
        rc.routeId = c["route_id"].get<std::string>();
        rc.isCompatible = c.value("is_compatible", true);
        rc.constraintType = c.value("constraint_type", "");
        rc.restrictionReason = c.value("restriction_reason", "");
        compat.push_back(rc);
    }
    return compat;
}

MmsSolver::Config MmsSolver::parseConfig(const json& input) {
    Config config;
    if (!input.contains("config")) return config;

    const auto& c = input["config"];
    config.maxSolveTimeSeconds = c.value("max_solve_time_seconds", 30);
    config.numWorkers = c.value("num_workers", 4);
    config.explanationVerbosity = c.value("explanation_verbosity", "STANDARD");

    if (c.contains("soft_constraint_penalties")) {
        const auto& p = c["soft_constraint_penalties"];
        config.mileageImbalancePenalty = p.value("mileage_imbalance", 100);
        config.preferenceViolationPenalty = p.value("preference_violation", 50);
        config.overtimeHoursPenalty = p.value("overtime_hours", 200);
    }

    return config;
}

// =============================================================================
// Helper Functions
// =============================================================================

size_t MmsSolver::findTrainIndex(const std::vector<Train>& trains, const std::string& id) const {
    for (size_t i = 0; i < trains.size(); ++i) {
        if (trains[i].id == id) return i;
    }
    return trains.size(); // Not found
}

size_t MmsSolver::findRouteIndex(const std::vector<Route>& routes, const std::string& id) const {
    for (size_t i = 0; i < routes.size(); ++i) {
        if (routes[i].id == id) return i;
    }
    return routes.size(); // Not found
}

bool MmsSolver::isFleetAllowed(const Train& train, const Route& route) const {
    if (route.allowedFleets.empty()) {
        return true; // No restrictions
    }
    return std::find(route.allowedFleets.begin(), route.allowedFleets.end(),
                     train.fleetId) != route.allowedFleets.end();
}

std::vector<ExplanationFactor> MmsSolver::generateExplanation(
    const Train& train,
    const Route& route,
    const json& input,
    double objectiveValue
) const {
    std::vector<ExplanationFactor> factors;

    // Mileage balance factor
    int variance = train.currentMileage - train.targetMileage;
    ExplanationFactor mileageFactor;
    mileageFactor.constraintType = "SOFT";
    mileageFactor.constraintName = "MILEAGE_BALANCE";
    mileageFactor.impact = static_cast<double>(std::abs(variance));

#ifdef HAS_FMT
    mileageFactor.description = fmt::format(
        "Train is {}km {} fleet target",
        std::abs(variance),
        variance < 0 ? "under" : "over"
    );
#else
    char desc[256];
    std::snprintf(desc, sizeof(desc), "Train is %dkm %s fleet target",
                  std::abs(variance), variance < 0 ? "under" : "over");
    mileageFactor.description = desc;
#endif

    factors.push_back(mileageFactor);

    // Route match advice
    int routeKm = route.expectedKm;
    std::string routeAdvice;

    if (variance < -1000 && routeKm > 300) {
        routeAdvice = "High-km route helps balance under-utilized train";
    } else if (variance > 1000 && routeKm < 150) {
        routeAdvice = "Low-km route reduces over-utilization";
    } else if (variance > 500 && routeKm > 200) {
        routeAdvice = "Consider lower-km route for over-utilized train";
    }

    if (!routeAdvice.empty()) {
        ExplanationFactor routeFactor;
        routeFactor.constraintType = "SOFT";
        routeFactor.constraintName = "ROUTE_MATCH";
        routeFactor.impact = static_cast<double>(routeKm);
        routeFactor.description = routeAdvice;
        factors.push_back(routeFactor);
    }

    // Check hard constraints that may have affected alternatives
    if (input.contains("hard_constraints")) {
        for (const auto& c : input["hard_constraints"]) {
            ExplanationFactor hardFactor;
            hardFactor.constraintType = "HARD";
            hardFactor.constraintName = c["type"].get<std::string>();
            hardFactor.impact = 0;

#ifdef HAS_FMT
            hardFactor.description = fmt::format(
                "Alternative train {} blocked: {}",
                c["train_id"].get<std::string>().substr(0, 8),
                c.value("description", "constraint active")
            );
#else
            std::string trainIdShort = c["train_id"].get<std::string>().substr(0, 8);
            std::string constraintDesc = c.value("description", "constraint active");
            char hardDesc[256];
            std::snprintf(hardDesc, sizeof(hardDesc), "Alternative train %s blocked: %s",
                          trainIdShort.c_str(), constraintDesc.c_str());
            hardFactor.description = hardDesc;
#endif

            factors.push_back(hardFactor);
        }
    }

    return factors;
}

std::vector<Unassigned> MmsSolver::findUnassigned(
    const std::vector<Train>& trains,
    const std::vector<Route>& routes,
    const std::vector<Assignment>& assignments,
    const json& input
) const {
    std::vector<Unassigned> result;

    // Find assigned train IDs
    std::unordered_map<std::string, bool> assignedTrains;
    for (const auto& a : assignments) {
        assignedTrains[a.trainId] = true;
    }

    // Check for unassigned trains
    for (const auto& train : trains) {
        if (assignedTrains.find(train.id) == assignedTrains.end()) {
            Unassigned u;
            u.trainId = train.id;

            // Determine reason
            if (train.fitnessStatus == "GROUNDED") {
                u.reason = "Train is GROUNDED";
                u.blockingConstraints.push_back("FITNESS_STATUS");
            } else if (train.fitnessStatus == "RESTRICTED") {
                u.reason = "Train has RESTRICTED status";
                u.blockingConstraints.push_back("FITNESS_STATUS");
            } else {
                u.reason = "No compatible route with capacity";
            }

            result.push_back(u);
        }
    }

    // Check for unfilled route requirements
    std::unordered_map<std::string, int> routeAssignments;
    for (const auto& a : assignments) {
        routeAssignments[a.routeId]++;
    }

    for (const auto& route : routes) {
        int assigned = routeAssignments[route.id];
        if (assigned < route.requiredTrains) {
            Unassigned u;
            u.routeId = route.id;
            u.shortfall = route.requiredTrains - assigned;
            u.reason = "Insufficient trains for route requirement";
            result.push_back(u);
        }
    }

    return result;
}

std::vector<MaterialWarning> MmsSolver::checkMaterialWarnings(const json& input) const {
    std::vector<MaterialWarning> warnings;

    if (!input.contains("pending_pms") || !input.contains("material_positions")) {
        return warnings;
    }

    // Build material inventory map
    std::unordered_map<std::string, int> inventory;
    for (const auto& pos : input["material_positions"]) {
        std::string key = pos["depot_id"].get<std::string>() + ":" +
                          pos["part_number"].get<std::string>();
        inventory[key] = pos.value("quantity_available", 0);
    }

    // Check pending PMs for material issues
    for (const auto& pm : input["pending_pms"]) {
        if (!pm.contains("required_materials")) continue;

        for (const auto& mat : pm["required_materials"]) {
            std::string partNumber = mat["part_number"].get<std::string>();
            int required = mat.value("quantity", 1);
            std::string criticality = mat.value("criticality", "CONSUMABLE");

            // Assume first depot for simplicity (real impl would check PM's depot)
            bool found = false;
            for (const auto& pos : input["material_positions"]) {
                if (pos["part_number"].get<std::string>() == partNumber) {
                    int available = pos.value("quantity_available", 0);
                    if (available < required) {
                        MaterialWarning warning;
                        warning.pmId = pm["pm_id"].get<std::string>();
                        warning.trainId = pm["train_id"].get<std::string>();
                        warning.partNumber = partNumber;

                        if (available == 0) {
                            warning.status = "UNAVAILABLE";
                            warning.description = "Part not in stock";
                        } else {
                            warning.status = "LOW_STOCK";

#ifdef HAS_FMT
                            warning.description = fmt::format(
                                "Only {} available, {} required",
                                available, required
                            );
#else
                            char warnDesc[128];
                            std::snprintf(warnDesc, sizeof(warnDesc),
                                "Only %d available, %d required", available, required);
                            warning.description = warnDesc;
#endif
                        }

                        warnings.push_back(warning);
                    }
                    found = true;
                    break;
                }
            }

            if (!found && criticality == "BLOCKING") {
                MaterialWarning warning;
                warning.pmId = pm["pm_id"].get<std::string>();
                warning.trainId = pm["train_id"].get<std::string>();
                warning.partNumber = partNumber;
                warning.status = "UNAVAILABLE";
                warning.description = "Blocking part not tracked in inventory";
                warnings.push_back(warning);
            }
        }
    }

    return warnings;
}

ResultSummary MmsSolver::buildSummary(
    const std::vector<Assignment>& assignments,
    const std::vector<Unassigned>& unassigned,
    double totalPenalty
) const {
    ResultSummary summary;
    summary.totalPenalty = totalPenalty;
    summary.trainsAssigned = static_cast<int>(assignments.size());

    // Count unassigned trains (not unfilled routes)
    int unassignedTrains = 0;
    for (const auto& u : unassigned) {
        if (u.trainId) {
            unassignedTrains++;
        }
    }
    summary.trainsUnassigned = unassignedTrains;

    // TODO: Detailed soft constraint breakdown from solver
    summary.softConstraintBreakdown["MILEAGE_BALANCE"] = totalPenalty * 0.8;
    summary.softConstraintBreakdown["PREFERENCE_VIOLATION"] = totalPenalty * 0.2;

    summary.materialBlocks = 0; // TODO: Count from warnings

    return summary;
}

} // namespace mms

